using Microsoft.EntityFrameworkCore;using Microsoft.EntityFrameworkCore.Metadata.Builders;using NutriCasa.Domain.Entities;
namespace NutriCasa.Infrastructure.Persistence.Configurations;
public class IngredientCatalogConfiguration : IEntityTypeConfiguration<IngredientCatalog>{public void Configure(EntityTypeBuilder<IngredientCatalog> builder){builder.ToTable("ingredient_catalog");builder.HasKey(e => e.Id);builder.Property(e => e.Id).HasColumnName("ingredient_id").HasDefaultValueSql("uuid_generate_v4()");builder.Property(e => e.Code).HasMaxLength(60).IsRequired();builder.Property(e => e.Name).HasMaxLength(100).IsRequired();builder.Property(e => e.NameSearch).HasMaxLength(100);builder.Property(e => e.Category).HasMaxLength(30).IsRequired();builder.Property(e => e.KcalPer100g).HasColumnType("decimal(7,2)");builder.Property(e => e.ProteinGPer100g).HasColumnType("decimal(6,2)");builder.Property(e => e.FatGPer100g).HasColumnType("decimal(6,2)");builder.Property(e => e.CarbsGPer100g).HasColumnType("decimal(6,2)");builder.Property(e => e.FiberGPer100g).HasColumnType("decimal(6,2)");builder.Property(e => e.AvgPriceMxn).HasColumnType("decimal(8,2)");builder.Property(e => e.AvgPriceUnit).HasMaxLength(20);builder.Property(e => e.UnitGramsEquivalent).HasColumnType("decimal(8,2)");builder.Property(e => e.PrimaryStoreCategory).HasMaxLength(50);builder.Property(e => e.SecondaryStoreCategory).HasMaxLength(50);builder.HasOne(e => e.UpdatedByUser).WithMany().HasForeignKey(e => e.UpdatedByUserId);builder.HasIndex(e => e.Code).IsUnique();builder.HasIndex(e => e.NameSearch);}}
